using System;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.Net.WebSockets;
using System.Text;
using System.Threading;
using System.Threading.Tasks;
using System.Web.Script.Serialization;
using GTA;
using GTA.Math;

namespace ModProject
{
    public class Mod : Script
    {
        private ClientWebSocket _webSocket;
        private CancellationTokenSource _cts;
        private readonly ConcurrentQueue<Action> _mainThreadActions = new ConcurrentQueue<Action>();
        private readonly JavaScriptSerializer _jsonSerializer = new JavaScriptSerializer();

        private DateTime _lastRepairUtc = DateTime.MinValue;
        private DateTime _lastBoostUtc = DateTime.MinValue;
        private const double CooldownSec = 10.0;
        private const float BoostForceMagnitude = 3000f;
        private const float MaxEngineHealth = 1000f;

        public Mod()
        {
            Interval = 100;
            Tick += OnTick;
            Aborted += OnAborted;

            _cts = new CancellationTokenSource();
            CancellationToken token = _cts.Token;
            Task.Run(() => WebSocketLoop(token), token);
        }

        private async Task WebSocketLoop(CancellationToken ct)
        {
            while (!ct.IsCancellationRequested)
            {
                try
                {
                    using (var ws = new ClientWebSocket())
                    {
                        _webSocket = ws;
                        await ws.ConnectAsync(new Uri("ws://127.0.0.1:60080"), ct);

                        string subMsg = "{\"type\":\"serviceSignalSub\",\"service\":\"IM_MESSAGE_TRANSPORT\"}";
                        byte[] subBytes = Encoding.UTF8.GetBytes(subMsg);
                        await ws.SendAsync(new ArraySegment<byte>(subBytes), WebSocketMessageType.Text, true, ct);

                        byte[] buffer = new byte[8192];
                        StringBuilder sb = new StringBuilder();

                        while (ws.State == WebSocketState.Open && !ct.IsCancellationRequested)
                        {
                            WebSocketReceiveResult result = await ws.ReceiveAsync(
                                new ArraySegment<byte>(buffer), ct);

                            if (result.MessageType == WebSocketMessageType.Close)
                                break;

                            sb.Append(Encoding.UTF8.GetString(buffer, 0, result.Count));

                            if (result.EndOfMessage)
                            {
                                string raw = sb.ToString();
                                sb.Clear();
                                ParseAndEnqueue(raw);
                            }
                        }
                    }
                }
                catch (OperationCanceledException)
                {
                    break;
                }
                catch
                {
                }

                _webSocket = null;

                if (!ct.IsCancellationRequested)
                {
                    try
                    {
                        await Task.Delay(3000, ct);
                    }
                    catch (OperationCanceledException)
                    {
                        break;
                    }
                }
            }
        }

        private void ParseAndEnqueue(string raw)
        {
            try
            {
                Dictionary<string, object> dict =
                    _jsonSerializer.Deserialize<Dictionary<string, object>>(raw);

                if (dict == null)
                    return;

                string msgType = null;
                if (dict.ContainsKey("messageType"))
                    msgType = dict["messageType"] as string;
                else if (dict.ContainsKey("type"))
                    msgType = dict["type"] as string;

                if (msgType != "WebcastChatMessage")
                    return;

                string content = null;

                if (dict.ContainsKey("content"))
                {
                    content = dict["content"] as string;
                }
                else if (dict.ContainsKey("data")
                    && dict["data"] is Dictionary<string, object> dataDict)
                {
                    if (dataDict.ContainsKey("content"))
                        content = dataDict["content"] as string;
                }

                if (!string.IsNullOrWhiteSpace(content))
                {
                    string cmd = content.Trim().ToLowerInvariant();
                    _mainThreadActions.Enqueue(() => ProcessCommand(cmd));
                }
            }
            catch
            {
            }
        }

        private void ProcessCommand(string cmd)
        {
            if (cmd == "repair")
                TryRepair();
            else if (cmd == "boost")
                TryBoost();
        }

        private void TryRepair()
        {
            DateTime now = DateTime.UtcNow;
            if ((now - _lastRepairUtc).TotalSeconds < CooldownSec)
                return;

            Vehicle vehicle = GetPlayerVehicle();
            if (vehicle == null)
                return;

            float current = vehicle.EngineHealth;
            float increase = current * 0.1f;
            float newHealth = current + increase;
            if (newHealth > MaxEngineHealth)
                newHealth = MaxEngineHealth;

            vehicle.EngineHealth = newHealth;
            _lastRepairUtc = now;
        }

        private void TryBoost()
        {
            DateTime now = DateTime.UtcNow;
            if ((now - _lastBoostUtc).TotalSeconds < CooldownSec)
                return;

            Vehicle vehicle = GetPlayerVehicle();
            if (vehicle == null)
                return;

            Vector3 forward = vehicle.ForwardVector;
            vehicle.ApplyForce(forward * BoostForceMagnitude, Vector3.Zero, ForceType.Force);
            _lastBoostUtc = now;
        }

        private Vehicle GetPlayerVehicle()
        {
            Player player = Game.Player;
            if (player == null)
                return null;

            Ped ped = player.Character;
            if (ped == null)
                return null;

            Vehicle vehicle = ped.CurrentVehicle;
            if (vehicle == null)
                return null;

            if (!vehicle.IsDriveable)
                return null;

            return vehicle;
        }

        private void OnTick(object sender, EventArgs e)
        {
            while (_mainThreadActions.TryDequeue(out Action action))
            {
                try
                {
                    action();
                }
                catch
                {
                }
            }
        }

        private void OnAborted(object sender, EventArgs e)
        {
            try
            {
                _cts?.Cancel();
                _cts?.Dispose();
            }
            catch
            {
            }

            try
            {
                _webSocket?.Dispose();
            }
            catch
            {
            }

            _webSocket = null;
            _lastRepairUtc = DateTime.MinValue;
            _lastBoostUtc = DateTime.MinValue;
        }
    }
}
